output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?carrier ?name WHERE {
  ?carrier wdt:P31 / wdt:P279 * wd:Q17205 .
  ?carrier wdt:P520 ?deliveryDate .
  FILTER NOT EXISTS {
    ?carrier wdt:P521 []
  }
  .
  FILTER NOT EXISTS {
    ?carrier wdt:P576 []
  }
  .
  OPTIONAL {
    ?carrier rdfs:label ?name .
    FILTER(lang(?name) = "en")
  }
}
ORDER BY ?name

